export const generateId = () => {
    try {
        if (typeof crypto !== 'undefined' && crypto.randomUUID) {
            return crypto.randomUUID();
        }
    } catch (e) {}
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
};

export const getData = <T,>(key: string): T[] => {
    try {
        const data = localStorage.getItem(key);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        return [];
    }
};

export const saveData = <T,>(key: string, data: T[]): boolean => {
    try {
        const timestamp = new Date().toISOString();
        const dataWithMeta = data.map(item => {
            if (item && typeof item === 'object') {
                const typed = item as any;
                let stableId = typed.id;
                if (key === 'users') stableId = typed.email || typed.username || typed.id;
                if (key === 'projects') stableId = typed.projectCode || typed.id;
                if (key === 'clients') stableId = typed.name || typed.id;

                return {
                    ...item,
                    id: stableId || generateId(),
                    updatedAt: typed.updatedAt || timestamp
                };
            }
            return item;
        });
        localStorage.setItem(key, JSON.stringify(dataWithMeta));
        return true;
    } catch (error) {
        return false;
    }
};

export const getSystemLogo = (): string | null => localStorage.getItem('system_logo');
export const saveSystemLogo = (base64Data: string | null): void => {
    if (base64Data) localStorage.setItem('system_logo', base64Data);
    else localStorage.removeItem('system_logo');
};

export interface SystemMeta {
    id: string;
    versionLabel: string;
    lastCloudSync?: string;
    syncApiKey: string; 
    autoSync: boolean;
    backupLocation?: string;
    driveFileId?: string;
    driveAccessToken?: string;
    googleClientId?: string; 
    connectedEmail?: string;
    driveFileUrl?: string;
}

const GLOBAL_ENV_CLIENT_ID = (import.meta as any).env?.VITE_GOOGLE_CLIENT_ID;
const HARDCODED_FALLBACK_ID = '674092109435-96p21r75k1jgr7t1f0l4eohf5c49k23t.apps.googleusercontent.com';
const MASTER_CLIENT_ID = GLOBAL_ENV_CLIENT_ID || HARDCODED_FALLBACK_ID;

export const getSystemMeta = (): SystemMeta => {
    const raw = localStorage.getItem('system_meta');

    const defaultMeta: SystemMeta = { 
        id: 'meta', 
        versionLabel: 'v4.5 Enterprise Cloud', 
        syncApiKey: '',
        autoSync: true,
        backupLocation: 'Google_Drive_AEWorks',
        googleClientId: MASTER_CLIENT_ID
    };

    const urlParams = new URLSearchParams(window.location.search);
    const urlClientId = urlParams.get('cid');

    if (urlClientId) {
        let existing: any = {};
        if (raw) {
            try {
                const parsed = JSON.parse(raw);
                existing = Array.isArray(parsed) ? parsed[0] : parsed;
            } catch (e) {}
        }
        localStorage.setItem('system_meta', JSON.stringify([{ ...defaultMeta, ...existing, googleClientId: urlClientId }]));
        const newUrl = window.location.pathname;
        window.history.replaceState({}, '', newUrl);
        return { ...defaultMeta, ...existing, googleClientId: urlClientId };
    }

    if (!raw) return defaultMeta;

    try {
        const data = JSON.parse(raw);
        const meta = Array.isArray(data) ? data[0] : data;

        if (meta.googleClientId !== MASTER_CLIENT_ID) {
            const updated = { ...defaultMeta, ...meta, googleClientId: MASTER_CLIENT_ID };
            localStorage.setItem('system_meta', JSON.stringify([updated]));
            return updated;
        }

        return { ...defaultMeta, ...meta };
    } catch {
        return defaultMeta;
    }
};

export const updateSystemMeta = (meta: Partial<SystemMeta>): void => {
    const current = getSystemMeta();
    localStorage.setItem('system_meta', JSON.stringify([{ ...current, ...meta }]));
};

export const DB_KEYS = ['clients', 'contacts', 'centres', 'framingMaterials', 'finishMaterials', 'projects', 'users', 'payrollRuns', 'defaultCostingVariables'];
const MASTER_FILE_NAME = "AEWORKS_MASTER_VAULT.json";

const getDriveHeaders = (token: string) => ({
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json'
});

export const syncWithCloud = async (providedToken?: string): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = providedToken || meta.driveAccessToken;

    if (!token) return { success: false, message: "Drive Authorization Required." };

    try {
        let email = meta.connectedEmail;
        try {
            const userRes = await fetch('https://www.googleapis.com/oauth2/v3/userinfo', { headers: getDriveHeaders(token) });
            if (userRes.ok) {
                const userData = await userRes.json();
                email = userData.email;
            }
        } catch (e) {}

        const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
        const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&spaces=drive&fields=files(id, name, modifiedTime, webViewLink)`, {
            headers: getDriveHeaders(token)
        });

        if (!searchRes.ok) {
            if (searchRes.status === 401) {
                updateSystemMeta({ driveAccessToken: undefined, connectedEmail: undefined });
                return { success: false, message: "Auth Session Expired." };
            }
            const errorBody = await searchRes.json().catch(() => ({}));
            throw new Error(errorBody.error?.message || `Drive Error: ${searchRes.status}`);
        }

        const searchData = await searchRes.json();
        let fileId = searchData.files?.[0]?.id;
        let fileUrl = searchData.files?.[0]?.webViewLink;

        if (!fileId) {
            updateSystemMeta({ driveAccessToken: token, connectedEmail: email });
            const pushResult = await pushToCloud();
            if (pushResult.success) {
                return { success: true, message: `Vault Initialized on Drive (${email})` };
            }
            return { success: true, message: `Connected as ${email}. Initial commit pending.` };
        }

        const fileRes = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
            headers: getDriveHeaders(token)
        });

        if (!fileRes.ok) throw new Error("Vault download failed.");

        const actualData = await fileRes.json();

        DB_KEYS.forEach(key => {
            const local = getData<any>(key);
            const remote = actualData[key] || [];
            const merged = mergeDatasets(key, local, remote);
            localStorage.setItem(key, JSON.stringify(merged));
        });

        if (actualData._branding?.logo) saveSystemLogo(actualData._branding.logo);

        updateSystemMeta({ 
            driveFileId: fileId, 
            driveAccessToken: token,
            driveFileUrl: fileUrl,
            connectedEmail: email,
            lastCloudSync: new Date().toISOString() 
        });

        return { success: true, message: `Cloud data merged for ${email}` };
    } catch (err: any) {
        console.error("Sync Failure:", err);
        return { success: false, message: err.message || "Cloud unreachable or network error." };
    }
};

export const pushToCloud = async (): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = meta.driveAccessToken;
    if (!token) return { success: false, message: "No active Drive link. Authorization required." };
    if (!navigator.onLine) return { success: false, message: "Device is offline. Cannot reach Drive." };

    try {
        const fullDB: any = {
            _branding: { logo: getSystemLogo() },
            _meta: { ...meta, lastPush: new Date().toISOString() }
        };
        DB_KEYS.forEach(key => fullDB[key] = getData(key));

        let fileId = meta.driveFileId;
        let fileUrl = meta.driveFileUrl;

        if (!fileId) {
            const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
            const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&fields=files(id, webViewLink)`, {
                headers: getDriveHeaders(token)
            });

            if (!searchRes.ok) {
                if (searchRes.status === 401) {
                    updateSystemMeta({ driveAccessToken: undefined });
                    return { success: false, message: "Authorization expired. Please re-link." };
                }
                const errorBody = await searchRes.json().catch(() => ({}));
                throw new Error(errorBody.error?.message || "Could not search for repository.");
            }

            const searchData = await searchRes.json();
            fileId = searchData.files?.[0]?.id;
            fileUrl = searchData.files?.[0]?.webViewLink;
        }

        if (!fileId) {
            const metadata = { name: MASTER_FILE_NAME, mimeType: 'application/json' };
            const createRes = await fetch('https://www.googleapis.com/drive/v3/files?fields=id,webViewLink', {
                method: 'POST',
                headers: getDriveHeaders(token),
                body: JSON.stringify(metadata)
            });
            if (!createRes.ok) {
                const errorBody = await createRes.json().catch(() => ({}));
                throw new Error(errorBody.error?.message || "Repository file creation failed.");
            }
            const createData = await createRes.json();
            fileId = createData.id;
            fileUrl = createData.webViewLink;
            updateSystemMeta({ driveFileId: fileId, driveFileUrl: fileUrl });
        }

        const uploadRes = await fetch(`https://www.googleapis.com/upload/drive/v3/files/${fileId}?uploadType=media`, {
            method: 'PATCH',
            headers: getDriveHeaders(token),
            body: JSON.stringify(fullDB)
        });

        if (!uploadRes.ok) {
            if (uploadRes.status === 401) {
                updateSystemMeta({ driveAccessToken: undefined });
                return { success: false, message: "Session expired while uploading." };
            }
            const errorBody = await uploadRes.json().catch(() => ({}));
            throw new Error(errorBody.error?.message || `Upload failed with status ${uploadRes.status}`);
        }

        updateSystemMeta({ lastCloudSync: new Date().toISOString(), driveFileUrl: fileUrl });
        return { success: true, message: "Synced to Drive successfully." };
    } catch (err: any) {
        return { success: false, message: err.message || "Unknown Cloud Error." };
    }
};

const mergeDatasets = (dbKey: string, local: any[], remote: any[]) => {
    const map = new Map();
    const getStableId = (item: any) => {
        if (dbKey === 'users') return item.email || item.username || item.id;
        if (dbKey === 'projects') return item.projectCode || item.id;
        if (dbKey === 'clients') return item.name || item.id;
        return item.id;
    };
    remote.forEach(remoteItem => {
        const id = getStableId(remoteItem);
        if (id) map.set(id, remoteItem);
    });
    local.forEach(localItem => {
        const id = getStableId(localItem);
        if (!id) return;
        const remoteItem = map.get(id);
        if (!remoteItem || new Date(localItem.updatedAt || 0) > new Date(remoteItem.updatedAt || 0)) {
            map.set(id, localItem);
        }
    });
    return Array.from(map.values());
};

import React, { useState, useRef, useEffect } from 'react';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { View, Project } from '../../types';
import ProjectListModal from './ProjectListModal';
import { useProjectContext } from '../../hooks/useProjectContext';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface ToolbarProps {
    setView: (view: View) => void;
}

const Toolbar: React.FC<ToolbarProps> = ({ setView }) => {
    const { 
        currentProject, projects, setProjects, setCurrentProject, resetProject,
        setClients, setContacts, setCentres, setFramingMaterials, setFinishMaterials,
        updateProject
    } = useProjectContext();

    const { currentUser, setCurrentUser, showNotification } = useAppContext();
    const [isProjectListOpen, setIsProjectListOpen] = useState(false);
    const [isDbMenuOpen, setIsDbMenuOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCommitting, setIsCommitting] = useState(false);
    const [syncError, setSyncError] = useState(false);
    const [systemMeta, setSystemMeta] = useState(db.getSystemMeta());

    const dbMenuRef = useRef<HTMLDivElement>(null);

    const isAdmin = currentUser?.role === 'admin';
    const isViewer = currentUser?.role === 'viewer';

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dbMenuRef.current && !dbMenuRef.current.contains(event.target as Node)) {
                setIsDbMenuOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const refreshAppState = () => {
        setProjects(db.getData('projects'));
        setClients(db.getData('clients'));
        setContacts(db.getData('contacts'));
        setCentres(db.getData('centres'));
        setFramingMaterials(db.getData('framingMaterials'));
        setFinishMaterials(db.getData('finishMaterials'));
        setSystemMeta(db.getSystemMeta());
    };

    const handleGoogleAuth = () => {
        const config = db.getSystemMeta();
        if (!config.googleClientId) {
            showNotification("Missing Google Client ID configuration.", "error");
            return;
        }

        setIsSyncing(true);
        try {
            const client = (window as any).google.accounts.oauth2.initTokenClient({
                client_id: config.googleClientId,
                scope: 'https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/userinfo.email',
                callback: async (response: any) => {
                    if (response.error) {
                        setIsSyncing(false);
                        showNotification(`Google Error: ${response.error}`, "error");
                        return;
                    }
                    showNotification("Establishing identity handshake...", "warning");
                    const result = await db.syncWithCloud(response.access_token);
                    setIsSyncing(false);
                    if (result.success) {
                        showNotification(result.message, 'success');
                        refreshAppState();
                    } else {
                        showNotification(result.message, 'warning');
                    }
                }
            });
            client.requestAccessToken();
        } catch (e) {
            setIsSyncing(false);
            showNotification("Auth System Offline.", "error");
        }
    };

    const handleManualSync = async () => {
        if (!systemMeta.driveAccessToken) {
            handleGoogleAuth();
            return;
        }
        setIsSyncing(true);
        setSyncError(false);
        showNotification("Pulling latest cloud data...", "warning");
        const result = await db.syncWithCloud();
        setIsSyncing(false);
        if (result.success) {
            showNotification(`SUCCESS: Vault synchronized with Google Drive.`, "success");
            refreshAppState();
        } else {
            setSyncError(true);
            showNotification(`SYNC FAILED: ${result.message}`, "error");
        }
    };

    const handleSaveProject = async () => {
        if (isViewer) return;
        if (!currentProject.projName || currentProject.projName.trim() === '') {
            showNotification('Project Name Required.', 'error');
            return;
        }
        if (!currentProject.projectCode) {
            showNotification('Generating Code...', 'warning');
            return;
        }

        setIsCommitting(true);

        // 1. Save to local storage
        updateProject({ ...currentProject, updatedAt: new Date().toISOString() });

        const meta = db.getSystemMeta();
        if (meta.driveAccessToken) {
            showNotification("COMMITTING TO CLOUD REPOSITORY...", "warning");

            // 2. Synchronize with Google Drive
            const cloudResult = await db.pushToCloud();

            if (cloudResult.success) {
                showNotification(`SUCCESS: Project saved to Drive (${meta.connectedEmail})`, 'success');
                setSyncError(false);
            } else {
                // EXPLICIT FAILURE REPORTING: Notification type 'error' for cloud failure
                showNotification(`CLOUD SYNC FAILED: ${cloudResult.message}. Local copy preserved.`, 'error');
                setSyncError(true);
            }
            setSystemMeta(db.getSystemMeta());
        } else {
            showNotification(`LOCAL SAVE SUCCESSFUL: Link cloud for central repository synchronization.`, 'warning');
        }
        setIsCommitting(false);
    };

    const handleLoadProject = (projectCode: string) => {
        const projectToLoad = projects.find(p => p.projectCode === projectCode);
        if (projectToLoad) {
            setCurrentProject(projectToLoad);
            setIsProjectListOpen(false);
            showNotification(`Loaded Project: ${projectToLoad.projectCode}`);
        }
    };

    const handleLogout = () => {
        setCurrentUser(null);
    };

    const isCloudActive = !!systemMeta.driveAccessToken;
    const driveFileUrl = systemMeta.driveFileUrl || (systemMeta.driveFileId ? `https://drive.google.com/file/d/${systemMeta.driveFileId}/view` : null);

    let badgeClass = 'bg-slate-50 border-slate-200 text-slate-400 hover:bg-slate-100 hover:text-slate-600 shadow-inner';
    let dotClass = 'bg-slate-300';

    if (isSyncing || isCommitting) {
        badgeClass = 'bg-blue-50 border-blue-200 text-blue-600 animate-pulse shadow-md';
        dotClass = 'bg-blue-500 animate-ping';
    } else if (syncError) {
        badgeClass = 'bg-red-50 border-red-200 text-red-600 hover:bg-red-100 shadow-md';
        dotClass = 'bg-red-500 shadow-[0_0_5px_#ef4444]';
    } else if (isCloudActive) {
        badgeClass = 'bg-white border-green-200 text-green-700 hover:border-green-400 shadow-sm';
        dotClass = 'bg-green-500 shadow-[0_0_5px_#10b981]';
    }

    return (
        <>
            <div className="flex flex-row md:flex-wrap gap-1.5 mb-2 bg-white p-1.5 rounded-xl shadow-sm justify-start md:justify-between items-center relative z-[40] border border-slate-200">
                <div className="flex flex-row flex-nowrap gap-1.5 items-center flex-grow overflow-x-auto no-scrollbar">
                    {!isViewer && (
                        <Button onClick={handleSaveProject} variant="primary" icon={isCommitting ? "fas fa-sync animate-spin" : "fas fa-save"} disabled={isCommitting} size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">
                            {isCommitting ? 'Pushing...' : 'Commit'}
                        </Button>
                    )}
                    <Button onClick={() => setIsProjectListOpen(true)} variant="success" icon="fas fa-folder-open" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Load</Button>
                    {!isViewer && <Button onClick={resetProject} variant="warning" icon="fas fa-file" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">New</Button>}
                    <div className="hidden md:block w-px bg-slate-200 mx-1 h-5 flex-shrink-0"></div>
                    <Button onClick={() => setView(View.TRACKER)} variant="primary" icon="fas fa-columns" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Tracker</Button>
                </div>

                <div className="flex items-center gap-2">
                    <div className="flex flex-col items-end">
                        <div className="flex items-center gap-1">
                            <button onClick={handleManualSync} disabled={isSyncing || isCommitting} className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-[10px] font-black uppercase tracking-widest transition-all ${badgeClass}`}>
                                <div className={`w-1.5 h-1.5 rounded-full ${dotClass}`}></div>
                                <span className="hidden sm:inline">
                                    {isSyncing ? 'Syncing...' : syncError ? 'Re-link' : isCloudActive ? (systemMeta.connectedEmail ? `Linked: ${systemMeta.connectedEmail}` : 'Sync Data') : 'Establish Link'}
                                </span>
                            </button>
                            {driveFileUrl && (
                                <a href={driveFileUrl} target="_blank" rel="noopener noreferrer" className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors" title="Locate Repository on Google Drive">
                                    <Icon name="fas fa-external-link-alt" className="text-[10px]" />
                                </a>
                            )}
                        </div>
                    </div>

                    {!isViewer && (
                        <div className="relative" ref={dbMenuRef}>
                            <button onClick={() => setIsDbMenuOpen(!isDbMenuOpen)} className={`flex items-center gap-2 px-3 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-lg border transition-all ${isDbMenuOpen ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-700 border-slate-300'}`}>
                                <Icon name="fas fa-database" />
                                <span className="hidden sm:inline">Vault</span>
                            </button>
                            {isDbMenuOpen && (
                                <div className="absolute top-[calc(100%+4px)] right-0 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 py-1 z-[100] animate-fade-in origin-top-right">
                                    <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mb-1">Repositories</div>
                                    <button onClick={() => { setView(View.MANAGE_CLIENTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-building" className="text-indigo-600 w-4"/> Clients</button>
                                    <button onClick={() => { setView(View.MANAGE_CONTACTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-address-card" className="text-teal-600 w-4"/> Personnel</button>
                                    <button onClick={() => { setView(View.MANAGE_MATERIALS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-boxes" className="text-rose-600 w-4"/> Materials</button>
                                    {isAdmin && (
                                        <>
                                            <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mt-1 mb-1">Control</div>
                                            <button onClick={() => { setView(View.MANAGE_USERS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold"><Icon name="fas fa-user-shield" className="text-blue-700 w-4"/> Access Keys</button>
                                        </>
                                    )}
                                </div>
                            )}
                        </div>
                    )}

                    <button 
                        onClick={handleLogout} 
                        className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-slate-900 text-slate-400 hover:bg-red-600 hover:text-white transition-all shadow-sm group" 
                        title="Terminate Session"
                    >
                        <Icon name="fas fa-power-off" className="text-[10px]" />
                        <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">Logout</span>
                    </button>
                </div>
            </div>
            <ProjectListModal isOpen={isProjectListOpen} onClose={() => setIsProjectListOpen(false)} onLoadProject={handleLoadProject} projects={projects} />
        </>
    );
};

export default Toolbar;

export const generateId = () => {
    try {
        if (typeof crypto !== 'undefined' && crypto.randomUUID) {
            return crypto.randomUUID();
        }
    } catch (e) {}
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
};

export const getData = <T,>(key: string): T[] => {
    try {
        const data = localStorage.getItem(key);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        return [];
    }
};

export const saveData = <T,>(key: string, data: T[]): boolean => {
    try {
        const timestamp = new Date().toISOString();
        const dataWithMeta = data.map(item => {
            if (item && typeof item === 'object') {
                const typed = item as any;
                let stableId = typed.id;
                if (key === 'users') stableId = typed.email || typed.username || typed.id;
                if (key === 'projects') stableId = typed.projectCode || typed.id;
                if (key === 'clients') stableId = typed.name || typed.id;

                return {
                    ...item,
                    id: stableId || generateId(),
                    updatedAt: typed.updatedAt || timestamp
                };
            }
            return item;
        });
        localStorage.setItem(key, JSON.stringify(dataWithMeta));
        return true;
    } catch (error) {
        return false;
    }
};

export const getSystemLogo = (): string | null => localStorage.getItem('system_logo');
export const saveSystemLogo = (base64Data: string | null): void => {
    if (base64Data) localStorage.setItem('system_logo', base64Data);
    else localStorage.removeItem('system_logo');
};

export interface SystemMeta {
    id: string;
    versionLabel: string;
    lastCloudSync?: string;
    syncApiKey: string; 
    autoSync: boolean;
    backupLocation?: string;
    driveFileId?: string;
    driveAccessToken?: string;
    googleClientId?: string; 
    connectedEmail?: string;
    driveFileUrl?: string;
}

const GLOBAL_ENV_CLIENT_ID = (import.meta as any).env?.VITE_GOOGLE_CLIENT_ID;
const HARDCODED_FALLBACK_ID = '674092109435-96p21r75k1jgr7t1f0l4eohf5c49k23t.apps.googleusercontent.com';
const MASTER_CLIENT_ID = GLOBAL_ENV_CLIENT_ID || HARDCODED_FALLBACK_ID;

export const getSystemMeta = (): SystemMeta => {
    const raw = localStorage.getItem('system_meta');

    const defaultMeta: SystemMeta = { 
        id: 'meta', 
        versionLabel: 'v4.5 Enterprise Cloud', 
        syncApiKey: '',
        autoSync: true,
        backupLocation: 'Google_Drive_AEWorks',
        googleClientId: MASTER_CLIENT_ID
    };

    const urlParams = new URLSearchParams(window.location.search);
    const urlClientId = urlParams.get('cid');

    if (urlClientId) {
        let existing: any = {};
        if (raw) {
            try {
                const parsed = JSON.parse(raw);
                existing = Array.isArray(parsed) ? parsed[0] : parsed;
            } catch (e) {}
        }
        localStorage.setItem('system_meta', JSON.stringify([{ ...defaultMeta, ...existing, googleClientId: urlClientId }]));
        const newUrl = window.location.pathname;
        window.history.replaceState({}, '', newUrl);
        return { ...defaultMeta, ...existing, googleClientId: urlClientId };
    }

    if (!raw) return defaultMeta;

    try {
        const data = JSON.parse(raw);
        const meta = Array.isArray(data) ? data[0] : data;

        if (meta.googleClientId !== MASTER_CLIENT_ID) {
            const updated = { ...defaultMeta, ...meta, googleClientId: MASTER_CLIENT_ID };
            localStorage.setItem('system_meta', JSON.stringify([updated]));
            return updated;
        }

        return { ...defaultMeta, ...meta };
    } catch {
        return defaultMeta;
    }
};

export const updateSystemMeta = (meta: Partial<SystemMeta>): void => {
    const current = getSystemMeta();
    localStorage.setItem('system_meta', JSON.stringify([{ ...current, ...meta }]));
};

export const DB_KEYS = ['clients', 'contacts', 'centres', 'framingMaterials', 'finishMaterials', 'projects', 'users', 'payrollRuns', 'defaultCostingVariables'];
const MASTER_FILE_NAME = "AEWORKS_MASTER_VAULT.json";

const getDriveHeaders = (token: string) => ({
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json'
});

const extractErrorMessage = async (response: Response): Promise<string> => {
    try {
        const body = await response.json();
        return body.error?.message || `HTTP Error: ${response.status}`;
    } catch {
        return `Unexpected Status: ${response.status}`;
    }
};

export const syncWithCloud = async (providedToken?: string): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = providedToken || meta.driveAccessToken;

    if (!token) return { success: false, message: "Drive Authorization Required." };

    try {
        let email = meta.connectedEmail;
        try {
            const userRes = await fetch('https://www.googleapis.com/oauth2/v3/userinfo', { headers: getDriveHeaders(token) });
            if (userRes.ok) {
                const userData = await userRes.json();
                email = userData.email;
            }
        } catch (e) {}

        const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
        const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&spaces=drive&fields=files(id, name, modifiedTime, webViewLink)`, {
            headers: getDriveHeaders(token)
        });

        if (!searchRes.ok) {
            const msg = await extractErrorMessage(searchRes);
            if (searchRes.status === 401) {
                updateSystemMeta({ driveAccessToken: undefined, connectedEmail: undefined });
                return { success: false, message: `Auth Session Expired. (${msg})` };
            }
            throw new Error(msg);
        }

        const searchData = await searchRes.json();
        let fileId = searchData.files?.[0]?.id;
        let fileUrl = searchData.files?.[0]?.webViewLink;

        if (!fileId) {
            updateSystemMeta({ driveAccessToken: token, connectedEmail: email });
            const pushResult = await pushToCloud();
            if (pushResult.success) {
                return { success: true, message: `Vault Initialized on Drive (${email})` };
            }
            return { success: true, message: `Connected as ${email}. Initial commit pending.` };
        }

        const fileRes = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
            headers: getDriveHeaders(token)
        });

        if (!fileRes.ok) {
            const msg = await extractErrorMessage(fileRes);
            throw new Error(`Vault download failed: ${msg}`);
        }

        const actualData = await fileRes.json();

        DB_KEYS.forEach(key => {
            const local = getData<any>(key);
            const remote = actualData[key] || [];
            const merged = mergeDatasets(key, local, remote);
            localStorage.setItem(key, JSON.stringify(merged));
        });

        if (actualData._branding?.logo) saveSystemLogo(actualData._branding.logo);

        updateSystemMeta({ 
            driveFileId: fileId, 
            driveAccessToken: token,
            driveFileUrl: fileUrl,
            connectedEmail: email,
            lastCloudSync: new Date().toISOString() 
        });

        return { success: true, message: `Cloud data merged for ${email}` };
    } catch (err: any) {
        console.error("Sync Failure:", err);
        return { success: false, message: err.message || "Cloud unreachable or network error." };
    }
};

export const pushToCloud = async (): Promise<{success: boolean, message: string}> => {
    const meta = getSystemMeta();
    const token = meta.driveAccessToken;
    if (!token) return { success: false, message: "No active Drive link. Authorization required." };
    if (!navigator.onLine) return { success: false, message: "Device is offline. Cannot reach Drive." };

    try {
        const fullDB: any = {
            _branding: { logo: getSystemLogo() },
            _meta: { ...meta, lastPush: new Date().toISOString() }
        };
        DB_KEYS.forEach(key => fullDB[key] = getData(key));

        let fileId = meta.driveFileId;
        let fileUrl = meta.driveFileUrl;

        if (!fileId) {
            const query = encodeURIComponent(`name='${MASTER_FILE_NAME}' and trashed=false`);
            const searchRes = await fetch(`https://www.googleapis.com/drive/v3/files?q=${query}&fields=files(id, webViewLink)`, {
                headers: getDriveHeaders(token)
            });

            if (!searchRes.ok) {
                const msg = await extractErrorMessage(searchRes);
                if (searchRes.status === 401) {
                    updateSystemMeta({ driveAccessToken: undefined });
                    return { success: false, message: "Authorization expired. Please re-link." };
                }
                throw new Error(msg);
            }

            const searchData = await searchRes.json();
            fileId = searchData.files?.[0]?.id;
            fileUrl = searchData.files?.[0]?.webViewLink;
        }

        if (!fileId) {
            const metadata = { name: MASTER_FILE_NAME, mimeType: 'application/json' };
            const createRes = await fetch('https://www.googleapis.com/drive/v3/files?fields=id,webViewLink', {
                method: 'POST',
                headers: getDriveHeaders(token),
                body: JSON.stringify(metadata)
            });
            if (!createRes.ok) {
                const msg = await extractErrorMessage(createRes);
                throw new Error(msg);
            }
            const createData = await createRes.json();
            fileId = createData.id;
            fileUrl = createData.webViewLink;
            updateSystemMeta({ driveFileId: fileId, driveFileUrl: fileUrl });
        }

        const uploadRes = await fetch(`https://www.googleapis.com/upload/drive/v3/files/${fileId}?uploadType=media`, {
            method: 'PATCH',
            headers: getDriveHeaders(token),
            body: JSON.stringify(fullDB)
        });

        if (!uploadRes.ok) {
            const msg = await extractErrorMessage(uploadRes);
            if (uploadRes.status === 401) {
                updateSystemMeta({ driveAccessToken: undefined });
                return { success: false, message: "Session expired while uploading." };
            }
            throw new Error(msg);
        }

        updateSystemMeta({ lastCloudSync: new Date().toISOString(), driveFileUrl: fileUrl });
        return { success: true, message: "Synced to Drive successfully." };
    } catch (err: any) {
        return { success: false, message: err.message || "Unknown Cloud Error." };
    }
};

const mergeDatasets = (dbKey: string, local: any[], remote: any[]) => {
    const map = new Map();
    const getStableId = (item: any) => {
        if (dbKey === 'users') return item.email || item.username || item.id;
        if (dbKey === 'projects') return item.projectCode || item.id;
        if (dbKey === 'clients') return item.name || item.id;
        return item.id;
    };
    remote.forEach(remoteItem => {
        const id = getStableId(remoteItem);
        if (id) map.set(id, remoteItem);
    });
    local.forEach(localItem => {
        const id = getStableId(localItem);
        if (!id) return;
        const remoteItem = map.get(id);
        if (!remoteItem || new Date(localItem.updatedAt || 0) > new Date(remoteItem.updatedAt || 0)) {
            map.set(id, localItem);
        }
    });
    return Array.from(map.values());
};

import React, { useState, useEffect } from 'react';
import Icon from './Icon';
import { Notification as NotificationType } from '../../types';

const Notification: React.FC<NotificationType> = ({ message, type }) => {
    const [show, setShow] = useState(false);

    useEffect(() => {
        setShow(true);
        // Errors persist longer to allow reading/copying URLs and instructions
        const duration = type === 'error' ? 10000 : 3800;
        const timer = setTimeout(() => setShow(false), duration);
        return () => clearTimeout(timer);
    }, [message, type]);

    const baseClasses = "fixed top-5 right-5 p-4 rounded-lg font-medium z-50 flex items-start gap-3 shadow-xl transition-transform duration-300 ease-in-out max-w-md w-full sm:w-auto";

    const typeClasses: { [key in NotificationType['type']]: string } = {
        success: 'bg-green-700 text-white',
        error: 'bg-red-700 text-white',
        warning: 'bg-amber-500 text-black',
    };

    const iconClasses: { [key in NotificationType['type']]: string } = {
        success: 'fas fa-check-circle',
        error: 'fas fa-exclamation-circle',
        warning: 'fas fa-exclamation-triangle',
    };

    const transformClass = show ? 'translate-x-0' : 'translate-x-[120%]';

    return (
        <div className={`${baseClasses} ${typeClasses[type]} ${transformClass}`}>
            <Icon name={iconClasses[type]} className="text-xl mt-0.5 shrink-0" />
            <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase opacity-60 mb-1 tracking-widest">{type === 'error' ? 'Critical Exception' : 'System Update'}</span>
                <span className="text-xs leading-relaxed whitespace-pre-wrap break-words">{message}</span>
            </div>
        </div>
    );
};

export default Notification;

import React, { useState, useRef, useEffect } from 'react';
import Button from '../ui/Button';
import Icon from '../ui/Icon';
import { View, Project } from '../../types';
import ProjectListModal from './ProjectListModal';
import { useProjectContext } from '../../hooks/useProjectContext';
import { useAppContext } from '../../hooks/useAppContext';
import * as db from '../../services/db';

interface ToolbarProps {
    setView: (view: View) => void;
}

const Toolbar: React.FC<ToolbarProps> = ({ setView }) => {
    const { 
        currentProject, projects, setProjects, setCurrentProject, resetProject,
        setClients, setContacts, setCentres, setFramingMaterials, setFinishMaterials,
        updateProject
    } = useProjectContext();

    const { currentUser, setCurrentUser, showNotification } = useAppContext();
    const [isProjectListOpen, setIsProjectListOpen] = useState(false);
    const [isDbMenuOpen, setIsDbMenuOpen] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCommitting, setIsCommitting] = useState(false);
    const [commitStatus, setCommitStatus] = useState<'idle' | 'saving' | 'syncing'>('idle');
    const [syncError, setSyncError] = useState(false);
    const [systemMeta, setSystemMeta] = useState(db.getSystemMeta());

    const dbMenuRef = useRef<HTMLDivElement>(null);

    const isAdmin = currentUser?.role === 'admin';
    const isViewer = currentUser?.role === 'viewer';

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dbMenuRef.current && !dbMenuRef.current.contains(event.target as Node)) {
                setIsDbMenuOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const refreshAppState = () => {
        setProjects(db.getData('projects'));
        setClients(db.getData('clients'));
        setContacts(db.getData('contacts'));
        setCentres(db.getData('centres'));
        setFramingMaterials(db.getData('framingMaterials'));
        setFinishMaterials(db.getData('finishMaterials'));
        setSystemMeta(db.getSystemMeta());
    };

    const handleGoogleAuth = () => {
        const config = db.getSystemMeta();
        if (!config.googleClientId) {
            showNotification("Missing Google Client ID configuration.", "error");
            return;
        }

        setIsSyncing(true);
        try {
            const client = (window as any).google.accounts.oauth2.initTokenClient({
                client_id: config.googleClientId,
                scope: 'https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/userinfo.email',
                callback: async (response: any) => {
                    if (response.error) {
                        setIsSyncing(false);
                        showNotification(`Google Error: ${response.error}`, "error");
                        return;
                    }
                    showNotification("Establishing identity handshake...", "warning");
                    const result = await db.syncWithCloud(response.access_token);
                    setIsSyncing(false);
                    if (result.success) {
                        showNotification(result.message, 'success');
                        refreshAppState();
                    } else {
                        showNotification(result.message, 'warning');
                    }
                }
            });
            client.requestAccessToken();
        } catch (e) {
            setIsSyncing(false);
            showNotification("Auth System Offline.", "error");
        }
    };

    const handleManualSync = async () => {
        if (!systemMeta.driveAccessToken) {
            handleGoogleAuth();
            return;
        }
        setIsSyncing(true);
        setSyncError(false);
        showNotification("Pulling latest cloud data...", "warning");
        const result = await db.syncWithCloud();
        setIsSyncing(false);
        if (result.success) {
            showNotification(`SUCCESS: Vault synchronized with Google Drive.`, "success");
            refreshAppState();
        } else {
            setSyncError(true);
            showNotification(`SYNC FAILED: ${result.message}`, "error");
        }
    };

    const handleSaveProject = async () => {
        if (isViewer) return;
        if (!currentProject.projName || currentProject.projName.trim() === '') {
            showNotification('Project Name Required.', 'error');
            return;
        }

        setIsCommitting(true);
        setCommitStatus('saving');

        // 1. Save to local storage
        try {
            updateProject({ ...currentProject, updatedAt: new Date().toISOString() });
        } catch (e: any) {
            showNotification(`Local save failed: ${e.message}`, 'error');
            setIsCommitting(false);
            setCommitStatus('idle');
            return;
        }

        const meta = db.getSystemMeta();
        if (meta.driveAccessToken) {
            setCommitStatus('syncing');
            showNotification("Synchronizing with cloud repository...", "warning");

            // 2. Synchronize with Google Drive
            const cloudResult = await db.pushToCloud();

            if (cloudResult.success) {
                showNotification(`SUCCESS: Project saved to Drive (${meta.connectedEmail})`, 'success');
                setSyncError(false);
            } else {
                // EXPLICIT FAILURE REPORTING: notification type 'error' for cloud failure
                showNotification(`CLOUD REPOSITORY ERROR: ${cloudResult.message}. Local copy preserved.`, 'error');
                setSyncError(true);
            }
            setSystemMeta(db.getSystemMeta());
        } else {
            showNotification(`LOCAL SAVE SUCCESSFUL: Link cloud for central repository synchronization.`, 'warning');
        }

        setIsCommitting(false);
        setCommitStatus('idle');
    };

    const handleLoadProject = (projectCode: string) => {
        const projectToLoad = projects.find(p => p.projectCode === projectCode);
        if (projectToLoad) {
            setCurrentProject(projectToLoad);
            setIsProjectListOpen(false);
            showNotification(`Loaded Project: ${projectToLoad.projectCode}`);
        }
    };

    const handleLogout = () => {
        setCurrentUser(null);
    };

    const isCloudActive = !!systemMeta.driveAccessToken;
    const driveFileUrl = systemMeta.driveFileUrl || (systemMeta.driveFileId ? `https://drive.google.com/file/d/${systemMeta.driveFileId}/view` : null);

    let badgeClass = 'bg-slate-50 border-slate-200 text-slate-400 hover:bg-slate-100 hover:text-slate-600 shadow-inner';
    let dotClass = 'bg-slate-300';

    if (isSyncing || isCommitting) {
        badgeClass = 'bg-blue-50 border-blue-200 text-blue-600 animate-pulse shadow-md';
        dotClass = 'bg-blue-500 animate-ping';
    } else if (syncError) {
        badgeClass = 'bg-red-50 border-red-200 text-red-600 hover:bg-red-100 shadow-md';
        dotClass = 'bg-red-500 shadow-[0_0_5px_#ef4444]';
    } else if (isCloudActive) {
        badgeClass = 'bg-white border-green-200 text-green-700 hover:border-green-400 shadow-sm';
        dotClass = 'bg-green-500 shadow-[0_0_5px_#10b981]';
    }

    return (
        <>
            <div className="flex flex-row md:flex-wrap gap-1.5 mb-2 bg-white p-1.5 rounded-xl shadow-sm justify-start md:justify-between items-center relative z-[40] border border-slate-200">
                <div className="flex flex-row flex-nowrap gap-1.5 items-center flex-grow overflow-x-auto no-scrollbar">
                    {!isViewer && (
                        <Button onClick={handleSaveProject} variant="primary" icon={isCommitting ? "fas fa-sync animate-spin" : "fas fa-save"} disabled={isCommitting} size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">
                            {commitStatus === 'saving' ? 'Saving...' : commitStatus === 'syncing' ? 'Syncing...' : 'Commit'}
                        </Button>
                    )}
                    <Button onClick={() => setIsProjectListOpen(true)} variant="success" icon="fas fa-folder-open" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Load</Button>
                    {!isViewer && <Button onClick={resetProject} variant="warning" icon="fas fa-file" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">New</Button>}
                    <div className="hidden md:block w-px bg-slate-200 mx-1 h-5 flex-shrink-0"></div>
                    <Button onClick={() => setView(View.TRACKER)} variant="primary" icon="fas fa-columns" size="sm" className="whitespace-nowrap py-1.5 px-3 text-[10px] uppercase font-black">Tracker</Button>
                </div>

                <div className="flex items-center gap-2">
                    <div className="flex flex-col items-end">
                        <div className="flex items-center gap-1">
                            <button onClick={handleManualSync} disabled={isSyncing || isCommitting} className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-[10px] font-black uppercase tracking-widest transition-all ${badgeClass}`}>
                                <div className={`w-1.5 h-1.5 rounded-full ${dotClass}`}></div>
                                <span className="hidden sm:inline">
                                    {isSyncing ? 'Syncing...' : syncError ? 'Re-link' : isCloudActive ? (systemMeta.connectedEmail ? `Linked: ${systemMeta.connectedEmail}` : 'Sync Data') : 'Establish Link'}
                                </span>
                            </button>
                            {driveFileUrl && (
                                <a href={driveFileUrl} target="_blank" rel="noopener noreferrer" className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors" title="Locate Repository on Google Drive">
                                    <Icon name="fas fa-external-link-alt" className="text-[10px]" />
                                </a>
                            )}
                        </div>
                    </div>

                    {!isViewer && (
                        <div className="relative" ref={dbMenuRef}>
                            <button onClick={() => setIsDbMenuOpen(!isDbMenuOpen)} className={`flex items-center gap-2 px-3 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-lg border transition-all ${isDbMenuOpen ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-700 border-slate-300'}`}>
                                <Icon name="fas fa-database" />
                                <span className="hidden sm:inline">Vault</span>
                            </button>
                            {isDbMenuOpen && (
                                <div className="absolute top-[calc(100%+4px)] right-0 w-64 bg-white rounded-xl shadow-2xl border border-slate-200 py-1 z-[100] animate-fade-in origin-top-right">
                                    <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mb-1">Repositories</div>
                                    <button onClick={() => { setView(View.MANAGE_CLIENTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-building" className="text-indigo-600 w-4"/> Clients</button>
                                    <button onClick={() => { setView(View.MANAGE_CONTACTS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-address-card" className="text-teal-600 w-4"/> Personnel</button>
                                    <button onClick={() => { setView(View.MANAGE_MATERIALS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold border-b border-slate-50"><Icon name="fas fa-boxes" className="text-rose-600 w-4"/> Materials</button>
                                    {isAdmin && (
                                        <>
                                            <div className="px-3 py-2 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mt-1 mb-1">Control</div>
                                            <button onClick={() => { setView(View.MANAGE_USERS); setIsDbMenuOpen(false); }} className="w-full text-left px-3 py-2.5 text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-3 font-bold"><Icon name="fas fa-user-shield" className="text-blue-700 w-4"/> Access Keys</button>
                                        </>
                                    )}
                                </div>
                            )}
                        </div>
                    )}

                    <button 
                        onClick={handleLogout} 
                        className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-slate-900 text-slate-400 hover:bg-red-600 hover:text-white transition-all shadow-sm group" 
                        title="Terminate Session"
                    >
                        <Icon name="fas fa-power-off" className="text-[10px]" />
                        <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">Logout</span>
                    </button>
                </div>
            </div>
            <ProjectListModal isOpen={isProjectListOpen} onClose={() => setIsProjectListOpen(false)} onLoadProject={handleLoadProject} projects={projects} />
        </>
    );
};

export default Toolbar;

import React, { useState, useEffect } from 'react';
import Icon from './Icon';
import { Notification as NotificationType } from '../../types';

const Notification: React.FC<NotificationType> = ({ message, type }) => {
    const [show, setShow] = useState(false);

    useEffect(() => {
        setShow(true);
        // Errors persist longer (10s) to allow reading/clicking URLs and instructions
        const duration = type === 'error' ? 10000 : 3800;
        const timer = setTimeout(() => setShow(false), duration);
        return () => clearTimeout(timer);
    }, [message, type]);

    const baseClasses = "fixed top-5 right-5 p-4 rounded-lg font-medium z-50 flex items-start gap-3 shadow-xl transition-transform duration-300 ease-in-out max-w-md w-full sm:w-auto border-l-4";

    const typeClasses: { [key in NotificationType['type']]: string } = {
        success: 'bg-green-700 text-white border-green-500',
        error: 'bg-red-800 text-white border-red-500',
        warning: 'bg-amber-500 text-black border-amber-400',
    };

    const iconClasses: { [key in NotificationType['type']]: string } = {
        success: 'fas fa-check-circle',
        error: 'fas fa-exclamation-circle',
        warning: 'fas fa-exclamation-triangle',
    };

    const transformClass = show ? 'translate-x-0' : 'translate-x-[120%]';

    // Helper to render text with clickable links
    const renderMessage = (text: string) => {
        const urlRegex = /(https?:\/\/[^\s]+)/g;
        const parts = text.split(urlRegex);

        return parts.map((part, i) => {
            if (part.match(urlRegex)) {
                return (
                    <a 
                        key={i} 
                        href={part} 
                        target="_blank" 
                        rel="noopener noreferrer" 
                        className="underline decoration-2 underline-offset-2 hover:text-blue-300 font-bold break-all inline-block mt-1"
                    >
                        {part} <Icon name="fas fa-external-link-alt" className="text-[10px] ml-1" />
                    </a>
                );
            }
            return <span key={i}>{part}</span>;
        });
    };

    return (
        <div className={`${baseClasses} ${typeClasses[type]} ${transformClass}`}>
            <Icon name={iconClasses[type]} className="text-xl mt-0.5 shrink-0" />
            <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase opacity-60 mb-1 tracking-widest">
                    {type === 'error' ? 'Critical Repository Exception' : 'System Update'}
                </span>
                <div className="text-xs leading-relaxed whitespace-pre-wrap">
                    {renderMessage(message)}
                </div>
            </div>
        </div>
    );
};

export default Notification;

export const generateId = () => {
